CREATE TABLE t1(a, b, c);
INSERT INTO t1 VALUES(1,2,3),(4,5,6),(7,8,9);
SELECT a, rank() OVER (PARTITION BY a ORDER BY b, c, a, b, c) FROM t1;
-- A query where the combined nBufferCol + pPartition->nExpr + pOrderBy->nExpr exceeds the ephemeral cursor column count triggers the overread.

CREATE TABLE t(x);
INSERT INTO t VALUES(1),(2),(3);
SELECT x, lead(x, 1) OVER (ORDER BY x) FROM t;
-- If iArgCol is misaligned with the actual ephemeral table schema, the OP_Column for the lead() function arguments reads past the record boundary.

CREATE TABLE t(a,b,c,d,e,f,g);
INSERT INTO t VALUES(1,2,3,4,5,6,7);
SELECT a, max(b+c+d+e+f+g) OVER (), min(a) OVER () FROM t;
-- If the register allocation for the first window function's arguments is smaller than windowArgCount returns, the second iteration's writes overflow.

CREATE TABLE t(a TEXT);
INSERT INTO t VALUES('hello');
ALTER TABLE t ADD COLUMN c TEXT NOT NULL DEFAULT (CASE WHEN 0=1 THEN 'valid' END);
-- The DEFAULT evaluates to NULL, but quick_check is skipped because:
--   pNew->pCheck == 0 (no CHECK constraints)
--   c is NOT generated
--   t is not STRICT
-- Existing row now has NULL in NOT NULL column c
SELECT c IS NULL FROM t; -- Returns 1 (true), constraint violated
